:host {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--dimension-size-600, 48px);
  padding: 0 var(--dimension-space-100);
  flex-shrink: 0;
  gap: var(--dimension-space-100);
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-tertiary);
  box-sizing: border-box;
}

/* Backgrounds */
:host(.bg-primary)     { background-color: var(--color-background-primary); }
:host(.bg-secondary)   { background-color: var(--color-background-secondary); }
:host(.bg-transparent) { background-color: transparent; }
:host(.bg-translucent) {
  background-color: var(--color-background-translucent);
  backdrop-filter: blur(var(--effect-blur-md));
  -webkit-backdrop-filter: blur(var(--effect-blur-md));
}

.left {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-100);
  flex-shrink: 0;
  min-width: 0;
}

.title {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.center {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--dimension-space-050);
  flex: 1;
  min-width: 0;
}

.right {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  flex-shrink: 0;
}

import { Component, Prop, h, Host } from '@stencil/core';

export type HeaderBackground = 'primary' | 'secondary' | 'transparent' | 'translucent';

@Component({
  tag: 'ds-header',
  styleUrl: 'Header.css',
  scoped: true,
})
export class Header {
  @Prop() heading: string | undefined;
  @Prop() background: HeaderBackground = 'secondary';

  render() {
    return (
      <Host
        class={{ header: true, [`bg-${this.background}`]: true }}
        role="banner"
      >
        <div class="left">
          <slot name="left" />
          {this.heading && <span class="title text-title-small">{this.heading}</span>}
        </div>
        <div class="center">
          <slot name="center" />
        </div>
        <div class="right">
          <slot name="right" />
        </div>
      </Host>
    );
  }
}
